#include <unordered_map>
#include <string>

class Solution {
public:
    std::string greatestLetter(std::string s) {
        std::unordered_map<char, int> countMap;

        for (char c : s) {
            countMap[c]++;
        }

        char result = 'a';
        for (char c : s) {
            if (countMap[c] > countMap[result] && isupper(c)) {
                result = c;
            }
        }

        return char(toupper(result));
    }
};
